    cin.tie(nullptr);

    int n;
    cin >> n;
    vector<pair<long long, long long>> a(n);
    for (int i = 0; i < n; i++) cin >> a[i].first >> a[i].second;

    sort(a.begin(), a.end(), [](const auto& lhs, const auto& rhs) {
        if (lhs.first != rhs.first) return lhs.first < rhs.first;
        return lhs.second > rhs.second;
    });

    vector<long long> tails;
    for (auto [w, h] : a) {
        auto it = lower_bound(tails.begin(), tails.end(), h);
        if (it == tails.end()) tails.push_back(h);
        else *it = h;
    }

    cout << tails.size() << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    int full = (1 << m) - 1;
    const long long INF = (long long)4e18;
    vector<long long> dp(1 << m, INF);
    dp[0] = 0;

    for (int i = 0; i < n; i++) {
        long long cost;
        int t;
        cin >> cost >> t;
        int mask = 0;
        for (int j = 0; j < t; j++) {
            int bulb;
            cin >> bulb;
            mask |= 1 << bulb;
        }
        vector<long long> ndp = dp;
        for (int state = 0; state <= full; state++) {
            if (dp[state] == INF) continue;
            ndp[state | mask] = min(ndp[state | mask], dp[state] + cost);
        }
        dp.swap(ndp);
    }

    cout << (dp[full] == INF ? -1 : dp[full]) << "\n";
    return 0;
}
